import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.HashMap;
import java.util.Map;

import org.apache.commons.csv.CSVRecord;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private CSVRecord csvRecord;
    private Map<String, Integer> mapping;
    private String[] values;

    @BeforeEach
    public void setUp() throws Exception {
        // Prepare mapping and values for constructor
        mapping = new HashMap<>();
        values = new String[] {"value1", "value2"};

        // Use reflection to invoke the package-private constructor
        csvRecord = createCSVRecord(values, mapping, "comment", 1L);
    }

    private CSVRecord createCSVRecord(String[] values, Map<String, Integer> mapping, String comment, long recordNumber) throws Exception {
        // CSVRecord constructor is package-private, so use reflection to create instance
        Class<CSVRecord> clazz = CSVRecord.class;
        var constructor = clazz.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
        return constructor.newInstance(values, mapping, comment, recordNumber);
    }

    @Test
    public void testIsSet_MappedAndIndexInRange_ReturnsTrue() {
        mapping.put("name1", 1);
        csvRecord = createCSVRecordWithMappingAndValues(mapping, new String[] {"v0", "v1", "v2"});

        assertTrue(csvRecord.isSet("name1"));
    }

    @Test
    public void testIsSet_MappedButIndexOutOfRange_ReturnsFalse() {
        mapping.put("name1", 3);
        csvRecord = createCSVRecordWithMappingAndValues(mapping, new String[] {"v0", "v1"});

        assertFalse(csvRecord.isSet("name1"));
    }

    @Test
    public void testIsSet_NotMapped_ReturnsFalse() {
        mapping.put("name1", 1);
        csvRecord = createCSVRecordWithMappingAndValues(mapping, new String[] {"v0", "v1"});

        assertFalse(csvRecord.isSet("unknown"));
    }

    @Test
    public void testIsSet_MappingNullValueIndex_ReturnsFalse() {
        mapping.put("name1", null);
        csvRecord = createCSVRecordWithMappingAndValues(mapping, new String[] {"v0", "v1"});

        // This will cause NullPointerException if not handled, but method does not handle null,
        // so test expects NPE or false? The method calls mapping.get(name).intValue() so NPE will happen.
        assertThrows(NullPointerException.class, () -> csvRecord.isSet("name1"));
    }

    private CSVRecord createCSVRecordWithMappingAndValues(Map<String, Integer> mapping, String[] values) {
        try {
            return createCSVRecord(values, mapping, "comment", 1L);
        } catch (Exception e) {
            fail("Failed to create CSVRecord instance: " + e.getMessage());
            return null;
        }
    }
}
